// === Build: Page Audit ===
// DOM-extracted fields come from the HTML node (immediate predecessor).
// Raw-HTML signals come from the fetch node (word count, images, links, schema).

const x    = $input.first().json;                            // extracted fields (HTML node)
const url  = $('Set: Target URL').first().json.url;          // requested URL (Node 1)
const html = $('Fetch: Live Page HTML').first().json.data;   // raw HTML (Node 2)

const toArr = v => Array.isArray(v) ? v.filter(s => s && String(s).trim())
                                    : (v && String(v).trim() ? [String(v)] : []);

let host = '';
const hostM = url.match(/^https?:\/\/([^\/]+)/i);
if (hostM) host = hostM[1].replace(/^www\./, '');

// --- title & meta ---
const title           = (x.title || '').trim();
const metaDescription = (x.metaDescription || '').trim();
const metaRobots      = (x.metaRobots || '').trim();
const canonical       = (x.canonical || '').trim();

// --- headings ---
const h1 = toArr(x.h1);
const h2 = toArr(x.h2);
const h3 = toArr(x.h3);

// --- word count (drop script/style first, then tags) ---
const bodyText = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&[a-z]+;/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();
const wordCount = bodyText ? bodyText.split(' ').length : 0;

// --- images (paired src + alt from raw HTML) ---
const imgTags = html.match(/<img\b[^>]*>/gi) || [];
const isContent = src => {
  if (!src) return false;
  const s = src.toLowerCase();
  if (s.endsWith('.svg')) return false;
  if (/\/icons?\//.test(s)) return false;
  if (/(arrow|icon|logo|sparkle|favicon)/.test(s)) return false;
  return /\.(jpe?g|png|webp|gif)(\?|$)/.test(s);
};
const images = imgTags.map(tag => {
  const srcM = tag.match(/\bsrc\s*=\s*["']([^"']*)["']/i);
  const altM = tag.match(/\balt\s*=\s*["']([^"']*)["']/i);
  return { src: srcM ? srcM[1] : '', alt: altM ? altM[1] : null };
});
const contentImages   = images.filter(i => isContent(i.src));
const imagesMissingAlt = contentImages
  .filter(i => !i.alt || !i.alt.trim())
  .map(i => i.src);

// --- links (internal vs external) ---
const linkTags = html.match(/<a\b[^>]*href\s*=\s*["'][^"']*["'][^>]*>/gi) || [];
let internalLinks = 0, externalLinks = 0;
for (const a of linkTags) {
  const m = a.match(/href\s*=\s*["']([^"']*)["']/i);
  if (!m) continue;
  const href = m[1];
  if (/^(#|mailto:|tel:|javascript:)/i.test(href)) continue;
  if (/^https?:\/\//i.test(href)) {
    (host && href.includes(host)) ? internalLinks++ : externalLinks++;
  } else {
    internalLinks++; // relative path
  }
}

// --- schema (parse JSON-LD from raw HTML, not the mangled node text) ---
const ldBlocks = html.match(/<script[^>]*type=["']application\/ld\+json["'][^>]*>[\s\S]*?<\/script>/gi) || [];
let schemaTypes = [];
let schemaValid = true;
for (const block of ldBlocks) {
  const inner = block.replace(/<script[^>]*>/i, '').replace(/<\/script>/i, '').trim();
  try {
    const parsed = JSON.parse(inner);
    const nodes = parsed['@graph'] || (Array.isArray(parsed) ? parsed : [parsed]);
    for (const n of nodes) {
      if (n && n['@type']) {
        Array.isArray(n['@type']) ? schemaTypes.push(...n['@type']) : schemaTypes.push(n['@type']);
      }
    }
  } catch (e) {
    schemaValid = false;
  }
}
schemaTypes = [...new Set(schemaTypes)];

// --- assemble single clean audit object ---
return [{
  json: {
    url, host,
    title, titleLength: title.length,
    metaDescription, metaDescriptionLength: metaDescription.length,
    metaRobots, canonical,
    h1, h1Count: h1.length,
    h2, h2Count: h2.length,
    h3, h3Count: h3.length,
    wordCount,
    imageCount: images.length,
    contentImageCount: contentImages.length,
    imagesMissingAltCount: imagesMissingAlt.length,
    imagesMissingAlt,
    internalLinks, externalLinks,
    schemaPresent: ldBlocks.length > 0,
    schemaValid, schemaTypes
  }
}];

// === Score: SEO Flags ===
// Deterministic SEO scoring. No LLM. Reads the page audit AND the GSC signals,
// applies fixed rules, emits a flat array of flags ordered by severity.
// Gemini later writes recommendation text against these flags — it does not score.

const a   = $('Build: Page Audit').first().json;
const gsc = $('Build: GSC Signals').first().json.gsc;

const SEV = { high: 3, medium: 2, low: 1 };
const flags = [];
const add = (category, severity, issue, detail) =>
  flags.push({ category, severity, issue, detail: detail ?? '' });

// --- Meta & Titles ---
if (!a.title) {
  add('Meta & Titles', 'high', 'Missing page title', 'No <title> tag found.');
} else {
  if (a.titleLength < 30)
    add('Meta & Titles', 'medium', 'Title too short',
        `${a.titleLength} chars. Aim for 30–60 to use the SERP space.`);
  if (a.titleLength > 60)
    add('Meta & Titles', 'medium', 'Title too long',
        `${a.titleLength} chars. Over ~60 risks truncation in search results.`);
}

if (!a.metaDescription) {
  add('Meta & Titles', 'high', 'Missing meta description',
      'No meta description. Google may auto-generate a worse snippet.');
} else {
  if (a.metaDescriptionLength < 70)
    add('Meta & Titles', 'medium', 'Meta description too short',
        `${a.metaDescriptionLength} chars. Aim for 70–155.`);
  if (a.metaDescriptionLength > 160)
    add('Meta & Titles', 'medium', 'Meta description too long',
        `${a.metaDescriptionLength} chars. Over ~160 gets truncated.`);
  const emojiCount = (a.metaDescription.match(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}\u{2B00}-\u{2BFF}]/gu) || []).length;
  if (emojiCount >= 3)
    add('Meta & Titles', 'low', 'Meta description is emoji-heavy',
        `${emojiCount} emoji. A few can help CTR; many read as spammy and dilute the message.`);
}

// --- Content & Headings ---
if (a.h1Count === 0)
  add('Content & Headings', 'high', 'Missing H1',
      'No H1 on the page. Every page should have one clear H1.');
if (a.h1Count > 1)
  add('Content & Headings', 'medium', 'Multiple H1 tags',
      `${a.h1Count} H1s found. Use one H1, then H2/H3 for structure.`);
if (a.h2Count === 0)
  add('Content & Headings', 'low', 'No H2 headings',
      'No H2s. Subheadings help structure and keyword coverage.');
if (a.wordCount < 300)
  add('Content & Headings', 'medium', 'Thin content',
      `${a.wordCount} words. Pages under ~300 words often struggle to rank.`);

// --- Images ---
if (a.imagesMissingAltCount > 0)
  add('Images', a.imagesMissingAltCount >= 3 ? 'medium' : 'low',
      'Images missing alt text',
      `${a.imagesMissingAltCount} of ${a.contentImageCount} content images have no alt text.`);

// --- Schema ---
if (!a.schemaPresent)
  add('Schema', 'low', 'No structured data',
      'No JSON-LD schema found. Schema can enable rich results.');
if (a.schemaPresent && !a.schemaValid)
  add('Schema', 'medium', 'Invalid structured data',
      'JSON-LD present but failed to parse. Broken schema is ignored by Google.');

// --- Internal Linking ---
if (a.internalLinks === 0)
  add('Internal Linking', 'medium', 'No internal links',
      'No internal links found. Internal links spread ranking signals.');
else if (a.internalLinks < 3)
  add('Internal Linking', 'low', 'Few internal links',
      `${a.internalLinks} internal links. Consider linking to related pages.`);

// --- Keyword Targeting (GSC-grounded; only when data exists) ---
if (gsc && gsc.hasData) {

  // striking distance: queries ranking 5–15 are the closest wins
  for (const q of gsc.strikingDistance.slice(0, 5)) {
    const inTitle = a.title.toLowerCase().includes(q.query.toLowerCase());
    add('Keyword Targeting',
        inTitle ? 'low' : 'high',
        `Striking-distance query: "${q.query}"`,
        `Position ${q.position.toFixed(1)}, ${q.impressions} impressions. ` +
        (inTitle
          ? 'Already in the title — refine the meta and content to push it up.'
          : 'Not in the title. Work this query into the title, H1, and meta to climb.'));
  }

  // high impressions, ~zero clicks: title/meta not earning the click
  for (const q of gsc.noClickHighImpression.slice(0, 3)) {
    add('Keyword Targeting', 'high',
        `High impressions, low CTR: "${q.query}"`,
        `${q.impressions} impressions at ${(q.ctr * 100).toFixed(1)}% CTR. ` +
        'The page shows up but the title/meta are not compelling enough to win the click.');
  }
}

// --- order by severity (high → low), stable within a tier ---
flags.sort((x, y) => SEV[y.severity] - SEV[x.severity]);

// --- summary counts for the frontend header ---
const summary = {
  url: a.url,
  totalFlags: flags.length,
  high:   flags.filter(f => f.severity === 'high').length,
  medium: flags.filter(f => f.severity === 'medium').length,
  low:    flags.filter(f => f.severity === 'low').length,
  categories: [...new Set(flags.map(f => f.category))],
  gscHasData: !!(gsc && gsc.hasData)
};

return [{ json: { summary, flags, audit: a, gsc } }];

// === Verify: Rewrites ===
// Deterministic check of Gemini's rewrites against the hard constraints.
// The LLM proposed; this node enforces. Each rewrite gets pass / needs_review
// with explicit reasons. Nothing here trusts the model's self-assessment.

// --- CONFIG: the brand name that must survive every rewrite ---
const BRAND = 'YOUR_BRAND';

const raw   = $input.first().json.text || '';
const audit = $('Score: SEO Flags').first().json.audit;

// --- strip code fences if Gemini wrapped the JSON despite instructions ---
const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

let rewrites;
try {
  rewrites = JSON.parse(cleaned);
} catch (e) {
  return [{ json: {
    parseError: true,
    message: 'Could not parse Gemini output as JSON.',
    rawPreview: cleaned.slice(0, 500)
  }}];
}
if (!Array.isArray(rewrites)) rewrites = [rewrites];

const countEmoji = s =>
  (String(s).match(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}\u{2B00}-\u{2BFF}]/gu) || []).length;
const hasBrand = (s, term) => new RegExp(term, 'i').test(String(s));

// --- verify one rewrite against the rule for its issue type ---
function verify(r) {
  const checks = [];
  const fail = m => checks.push(m);
  const issue = (r.issue || '').toLowerCase();
  const pr = r.proposedRewrite;

  // brand-name preservation applies to any text rewrite
  const textForBrand = typeof pr === 'string' ? pr
    : pr && typeof pr === 'object' ? Object.values(pr).join(' ') : '';
  if (textForBrand && new RegExp(BRAND, 'i').test(audit.title + audit.metaDescription) && !hasBrand(textForBrand, BRAND))
    fail('Brand name "' + BRAND + '" dropped from rewrite.');

  // --- meta description ---
  if (issue.includes('meta description')) {
    if (typeof pr !== 'string') { fail('Expected a string rewrite.'); }
    else {
      const len = pr.length;
      if (len < 70)  fail(`Too short: ${len} chars (min 70).`);
      if (len > 155) fail(`Too long: ${len} chars (max 155).`);
      const em = countEmoji(pr);
      if (em > 1) fail(`Too many emoji: ${em} (max 1).`);
    }
  }

  // --- title ---
  else if (issue.includes('title')) {
    if (typeof pr !== 'string') { fail('Expected a string rewrite.'); }
    else {
      const len = pr.length;
      if (len < 30) fail(`Too short: ${len} chars (min 30).`);
      if (len > 60) fail(`Too long: ${len} chars (max 60).`);
    }
  }

  // --- image alt text (object: filename -> alt) ---
  else if (issue.includes('alt text')) {
    if (!pr || typeof pr !== 'object') { fail('Expected an object mapping filenames to alt text.'); }
    else {
      const expected = audit.imagesMissingAlt || [];
      for (const file of expected)
        if (!(file in pr)) fail(`Missing alt suggestion for ${file}.`);
      for (const [file, alt] of Object.entries(pr)) {
        if (!alt || !String(alt).trim()) fail(`Empty alt for ${file}.`);
        else if (String(alt).length > 125) fail(`Alt too long for ${file}: ${String(alt).length} chars (max 125).`);
        else if (/^image of|^picture of|^photo of/i.test(String(alt).trim()))
          fail(`Alt for ${file} starts with a redundant prefix.`);
      }
    }
  }

  // flags with no single text fix (e.g. internal linking) — advice only
  // no proposedRewrite expected; nothing to verify

  return checks;
}

const verified = rewrites.map(r => {
  const issues = verify(r);
  return {
    ...r,
    status: issues.length === 0 ? 'pass' : 'needs_review',
    verifyIssues: issues
  };
});

// --- re-sort by severity so the final order is authoritative, not Gemini's ---
const SEV = { high: 3, medium: 2, low: 1 };
verified.sort((a, b) => (SEV[b.severity] || 0) - (SEV[a.severity] || 0));

// --- group into sections for the frontend ---
const sections = {};
for (const v of verified) {
  (sections[v.category] = sections[v.category] || []).push(v);
}

const summary = {
  url: audit.url,
  total: verified.length,
  passed: verified.filter(v => v.status === 'pass').length,
  needsReview: verified.filter(v => v.status === 'needs_review').length
};

return [{ json: { summary, sections, recommendations: verified, audit } }];

