// === Build: GSC Signals ===
// Turns GSC query rows into deterministic SEO signals for this page.
// Handles the no-rows case (new property, low-traffic page) as a normal
// path, not an error: returns hasData=false and empty arrays so the
// merge and scorer work whether or not GSC has data yet.

const inp = $input.first().json;
const url = $('Set: Target URL').first().json.url;

// GSC returns { rows: [...] } on success, or no rows key when empty (still 200).
const rows = Array.isArray(inp.rows) ? inp.rows : [];

// --- no data yet: return a valid, empty signal object ---
if (rows.length === 0) {
  return [{ json: {
    gsc: {
      hasData: false,
      url,
      totalClicks: 0,
      totalImpressions: 0,
      avgPosition: null,
      topQueries: [],
      strikingDistance: [],
      noClickHighImpression: []
    }
  }}];
}

// --- normalise rows (GSC key is an array because we queried by "query") ---
const queries = rows.map(r => ({
  query: Array.isArray(r.keys) ? r.keys[0] : String(r.keys || ''),
  clicks: r.clicks || 0,
  impressions: r.impressions || 0,
  ctr: r.ctr || 0,
  position: r.position || 0
}));

const totalClicks      = queries.reduce((s, q) => s + q.clicks, 0);
const totalImpressions = queries.reduce((s, q) => s + q.impressions, 0);
// impression-weighted average position (more meaningful than a flat mean)
const avgPosition = totalImpressions > 0
  ? queries.reduce((s, q) => s + q.position * q.impressions, 0) / totalImpressions
  : null;

// top queries by impressions, for context in the Gemini prompt
const topQueries = [...queries]
  .sort((a, b) => b.impressions - a.impressions)
  .slice(0, 10);

// striking distance: ranking 5–15 with real impressions = closest wins.
// these are the queries to aim the rewrites at.
const strikingDistance = queries
  .filter(q => q.position >= 5 && q.position <= 15 && q.impressions >= 10)
  .sort((a, b) => a.position - b.position);

// high impressions but almost no clicks = title/meta not compelling.
const noClickHighImpression = queries
  .filter(q => q.impressions >= 50 && q.ctr < 0.01)
  .sort((a, b) => b.impressions - a.impressions);

return [{ json: {
  gsc: {
    hasData: true,
    url,
    totalClicks,
    totalImpressions,
    avgPosition,
    topQueries,
    strikingDistance,
    noClickHighImpression
  }
}}];

// === Verify: Fixes ===
// Re-verifies the retried rewrites against the same hard constraints, then
// merges the corrected items back with the items that already passed.
// Outputs the same shape as Verify: Rewrites so both IF branches match.

// --- CONFIG: the brand name that must survive every rewrite ---
const BRAND = 'YOUR_BRAND';

const prev  = $('Verify: Rewrites').first().json;   // guaranteed to have run on this branch
const audit = prev.audit;
const gsc   = prev.gsc;
const original = prev.recommendations || [];

// --- parse the fix output defensively ---
const raw = $input.first().json.text || '';
const cleaned = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

let fixes = [];
let fixParseFailed = false;
try {
  fixes = JSON.parse(cleaned);
  if (!Array.isArray(fixes)) fixes = [fixes];
} catch (e) {
  fixParseFailed = true;
}

// --- verifier (same rules as Verify: Rewrites) ---
const countEmoji = s =>
  (String(s).match(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}\u{2B00}-\u{2BFF}]/gu) || []).length;

function verify(r) {
  const checks = [];
  const fail = m => checks.push(m);
  const issue = (r.issue || '').toLowerCase();
  const pr = r.proposedRewrite;

  const textForBrand = typeof pr === 'string' ? pr
    : pr && typeof pr === 'object' ? Object.values(pr).join(' ') : '';
  if (textForBrand && new RegExp(BRAND, 'i').test(audit.title + audit.metaDescription) && !new RegExp(BRAND, 'i').test(textForBrand))
    fail('Brand name "' + BRAND + '" dropped from rewrite.');

  if (issue.includes('meta description')) {
    if (typeof pr !== 'string') fail('Expected a string rewrite.');
    else {
      if (pr.length < 70)  fail(`Too short: ${pr.length} chars (min 70).`);
      if (pr.length > 155) fail(`Too long: ${pr.length} chars (max 155).`);
      if (countEmoji(pr) > 1) fail(`Too many emoji: ${countEmoji(pr)} (max 1).`);
    }
  } else if (issue.includes('title')) {
    if (typeof pr !== 'string') fail('Expected a string rewrite.');
    else {
      if (pr.length < 30) fail(`Too short: ${pr.length} chars (min 30).`);
      if (pr.length > 60) fail(`Too long: ${pr.length} chars (max 60).`);
    }
  } else if (issue.includes('alt text')) {
    if (!pr || typeof pr !== 'object') fail('Expected an object mapping filenames to alt text.');
    else {
      for (const file of (audit.imagesMissingAlt || []))
        if (!(file in pr)) fail(`Missing alt suggestion for ${file}.`);
      for (const [file, alt] of Object.entries(pr)) {
        if (!alt || !String(alt).trim()) fail(`Empty alt for ${file}.`);
        else if (String(alt).length > 125) fail(`Alt too long for ${file}: ${String(alt).length} chars (max 125).`);
        else if (/^image of|^picture of|^photo of/i.test(String(alt).trim()))
          fail(`Alt for ${file} starts with a redundant prefix.`);
      }
    }
  }
  return checks;
}

// --- re-verify each fixed item, keyed by issue ---
const fixedByIssue = {};
if (!fixParseFailed) {
  for (const f of fixes) {
    const issues = verify(f);
    fixedByIssue[f.issue] = {
      ...f,
      status: issues.length === 0 ? 'pass' : 'needs_review',
      verifyIssues: issues,
      retried: true
    };
  }
}

// --- merge: swap each originally-failed item for its fixed version ---
const merged = original.map(r => {
  if (r.status === 'needs_review' && fixedByIssue[r.issue]) return fixedByIssue[r.issue];
  return r;
});

// --- re-sort by severity ---
const SEV = { high: 3, medium: 2, low: 1 };
merged.sort((a, b) => (SEV[b.severity] || 0) - (SEV[a.severity] || 0));

// --- re-section ---
const sections = {};
for (const v of merged) {
  (sections[v.category] = sections[v.category] || []).push(v);
}

const summary = {
  url: audit.url,
  total: merged.length,
  passed: merged.filter(v => v.status === 'pass').length,
  needsReview: merged.filter(v => v.status === 'needs_review').length,
  retryApplied: true
};

return [{ json: { summary, sections, recommendations: merged, audit, gsc } }];
